Write-Phase 'Company Risk (daily)'
Invoke-Puller 'company-risk-scan --watchlist'  'Company risk watchlist'

# Phase 6: MarketMind Agent Analysis (daily)
# Runs auction, pair, PEAD, crowding, and strategy scoring for all thesis watchlist symbols.
# Writes alert notes to 05_Data_Pulls/Alerts/ for any symbol scoring >= 55.
# Requires agent-analyst.mjs to call scoreAndAlert() after runAgentsInParallel().
Write-Phase 'MarketMind Agent Analysis (daily)'
if ($SkipAgentScan) {
  Write-Host '  [skipped] agent scan disabled for this run.' -ForegroundColor DarkGray
} elseif ($DryRun) {
  Write-Host '  [dry-run] would run: node run.mjs agent-analyst --watchlist --score-and-alert' -ForegroundColor DarkGray
  Write-Host '  [dry-run] would run: node run.mjs agent-analyst --pairs-scan' -ForegroundColor DarkGray
} else {
  # Full watchlist scan with scoring and alert note generation
  Write-Host '  -> node run.mjs agent-analyst --watchlist --score-and-alert' -ForegroundColor Gray
  try {
    & node run.mjs agent-analyst --watchlist --score-and-alert 2>&1 | ForEach-Object { Write-Host $_ }
    if ($LASTEXITCODE -ne 0) { throw ('exit code ' + $LASTEXITCODE) }
    $script:succeeded++
  } catch {
    $msg = 'FAILED [agent-analyst watchlist]: ' + $_
    $script:errors.Add($msg)
    $script:failed++
    Write-Host ('  ' + $msg) -ForegroundColor Yellow
  }

  # Standalone pair scan (runs all configured watchlist pairs, not per-symbol)
  Write-Host '  -> node run.mjs agent-analyst --pairs-scan' -ForegroundColor Gray
  try {
    & node run.mjs agent-analyst --pairs-scan 2>&1 | ForEach-Object { Write-Host $_ }
    if ($LASTEXITCODE -ne 0) { throw ('exit code ' + $LASTEXITCODE) }
    $script:succeeded++
  } catch {
    $msg = 'FAILED [agent-analyst pairs-scan]: ' + $_
    $script:errors.Add($msg)
    $script:failed++
    Write-Host ('  ' + $msg) -ForegroundColor Yellow
  }
}

# ═══════════════════════════════════════════════════════════════════════════════
# WEEKLY PULLERS — run only with -IncludeWeekly
# ═══════════════════════════════════════════════════════════════════════════════

